+import {Options, RuleType} from '../rules';
+import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: number = 2;
+  minLevel: number = 2;
+  maxLevel: number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type Heading = { level: number, text: string, anchor: string };
+
+const startMarker = /^\\s*<!--\\s*toc\\s*-->\\s*$/i;
+const endMarker = /^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i;
+const atxHeading = /^(#{1,6})[ \	]+(.+?)\\s*$/;
+
+function withoutHeadingSuffix(text: string): string {
+  return text.replace(/\\s+#+\\s*$/, '').replace(/\\s*\\{#([^}\\s]+)\\}\\s*$/, '').trim();
+}
+
+function explicitId(text: string): string | undefined {
+  return text.match(/\\s*\\{#([^}\\s]+)\\}\\s*$/)?.[1];
+}
+
+function resolveLinks(text: string): string {
+  return text
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|]+)\\|([^\\]]+)\\]\\]/g, '$2')
+      .replace(/\\[\\[([^\\]]+)\\]\\]/g, '$1')
+      .replace(/\\[([^\\]]*)\\]\\([^)]*\\)/g, '$1');
+}
+
+function stripFormatting(text: string): string {
+  return resolveLinks(text)
+      .replace(/`([^`]*)`/g, '$1')
+      .replace(/(\\*\\*|__|~~)(.*?)\\1/g, '$2')
+      .replace(/[\\*_~]/g, '')
+      .replace(/<[^>]*>/g, '');
+}
+
+function createAnchor(text: string): string {
+  return stripFormatting(text)
+      .toLowerCase()
+      .replace(/\\s+/g, '-')
+      .replace(/[^a-z0-9_-]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-+|-+$/g, '');
+}
+
+function isExcluded(text: string, excludes: string[]): boolean {
+  return excludes.some((exclude) => {
+    const regex = exclude.match(/^\\/(.*)\\/$/);
+    if (regex) {
+      try {
+        return new RegExp(regex[1], 'i').test(text);
+      } catch (_) {
+        // Treat an invalid regular expression as a literal, just like any other entry.
+      }
+    }
+    return text.localeCompare(exclude, undefined, {sensitivity: 'accent'}) === 0;
+  });
+}
+
+function collectHeadings(lines: string[], tocStart: number, tocEnd: number, options: AutoTocOptions): Heading[] {
+  const headings: Heading[] = [];
+  const anchorCounts = new Map<string, number>();
+  let inYaml = lines[0]?.trim() === '---';
+  let fence: string | undefined;
+  let inMath = false;
+
+  for (let index = 0; index < lines.length; index++) {
+    const line = lines[index];
+    const trimmed = line.trim();
+
+    if (inYaml) {
+      if (index > 0 && (trimmed === '---' || trimmed === '...')) inYaml = false;
+      continue;
+    }
+    if (/^(`{3,}|~{3,})/.test(trimmed)) {
+      const marker = trimmed.match(/^(`{3,}|~{3,})/)?.[1];
+      if (!fence) fence = marker;
+      else if (marker?.[0] === fence[0] && marker.length >= fence.length) fence = undefined;
+      continue;
+    }
+    if (fence) continue;
+    if (/^\\${2,}\\s*$/.test(trimmed)) {
+      inMath = !inMath;
+      continue;
+    }
+    if (inMath || (index > tocStart && index < tocEnd)) continue;
+
+    const match = line.match(atxHeading);
+    if (!match) continue;
+    const level = match[1].length;
+    if (level < options.minLevel || level > options.maxLevel) continue;
+
+    const rawText = match[2];
+    const text = withoutHeadingSuffix(rawText);
+    const resolvedText = resolveLinks(text);
+    if (isExcluded(stripFormatting(resolvedText), options.excludeHeadings)) continue;
+
+    const base = options.useExplicitIds ? explicitId(rawText) ?? createAnchor(text) : createAnchor(text);
+    const count = anchorCounts.get(base) ?? 0;
+    anchorCounts.set(base, count + 1);
+    headings.push({level, text: options.stripFormattingInToc ? stripFormatting(resolvedText) : resolvedText, anchor: count ? `${base}-${count}` : base});
+  }
+  return headings;
+}
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+    });
+  }
+  get OptionsClass(): new () => AutoTocOptions { return AutoTocOptions; }
+  apply(text: string, options: AutoTocOptions): string {
+    const lines = text.split('\
');
+    const start = lines.findIndex((line) => startMarker.test(line));
+    if (start === -1) return text;
+    const endAfterStart = lines.findIndex((line, index) => index > start && endMarker.test(line));
+    const end = endAfterStart === -1 ? start : endAfterStart;
+    const headings = collectHeadings(lines, start, endAfterStart === -1 ? start : end, options);
+    const tocLines: string[] = [lines[start].trim(), ''];
+    if (options.title) tocLines.push(options.title, '');
+    headings.forEach((heading, index) => {
+      const indent = ' '.repeat(Math.max(0, heading.level - options.minLevel) * options.indentSize);
+      const indicator = options.listStyle === 'number' ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.` : options.bulletMarker;
+      tocLines.push(`${indent}${indicator} [${heading.text}](#${heading.anchor})`);
+    });
+    tocLines.push('', '<!-- /toc -->', '');
+    lines.splice(start, end - start + 1, ...tocLines);
+    return lines.join('\
');
+  }
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] { return []; }
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [
+      new DropdownOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.list-style.name', descriptionKey: 'rules.auto-toc.list-style.description', optionsKey: 'listStyle', records: [{value: 'bullet', description: 'Bullet list'}, {value: 'number', description: 'Numbered list'}]}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.bullet-marker.name', descriptionKey: 'rules.auto-toc.bullet-marker.description', optionsKey: 'bulletMarker'}),
+      new DropdownOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.ordered-list-style.name', descriptionKey: 'rules.auto-toc.ordered-list-style.description', optionsKey: 'orderedListStyle', records: [{value: 'always-one', description: 'Always use 1'}, {value: 'increment', description: 'Increment'}]}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.indent-size.name', descriptionKey: 'rules.auto-toc.indent-size.description', optionsKey: 'indentSize'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.min-level.name', descriptionKey: 'rules.auto-toc.min-level.description', optionsKey: 'minLevel'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.max-level.name', descriptionKey: 'rules.auto-toc.max-level.description', optionsKey: 'maxLevel'}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.title.name', descriptionKey: 'rules.auto-toc.title.description', optionsKey: 'title'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.use-explicit-ids.name', descriptionKey: 'rules.auto-toc.use-explicit-ids.description', optionsKey: 'useExplicitIds'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.strip-formatting-in-toc.name', descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description', optionsKey: 'stripFormattingInToc'}),
+      new TextAreaOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.exclude-headings.name', descriptionKey: 'rules.auto-toc.exclude-headings.description', optionsKey: 'excludeHeadings'}),
+    ];
+  }
+}
